import { db } from "@/db";
import { styles, stylePages, corpusImages } from "@/db/schema";
import { eq } from "drizzle-orm";
import { notFound } from "next/navigation";
import { StyleDetailClient } from "./StyleDetailClient";

export default async function StylePage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;

  const style = await db.select().from(styles).where(eq(styles.id, id)).get();
  if (!style) notFound();

  const pages = await db
    .select()
    .from(stylePages)
    .where(eq(stylePages.styleId, id));

  const images = await db
    .select()
    .from(corpusImages)
    .where(eq(corpusImages.styleId, id));

  let forkedFromName: string | null = null;
  if (style.forkedFromId) {
    const parent = await db
      .select({ name: styles.name })
      .from(styles)
      .where(eq(styles.id, style.forkedFromId))
      .get();
    forkedFromName = parent?.name ?? null;
  }

  return (
    <StyleDetailClient
      style={style}
      pages={pages}
      images={images}
      forkedFromName={forkedFromName}
    />
  );
}
